firebase(model,row,action) {
          console.log(row)
          var myFrom        ='/helpers/Form/selectFrom';
          var actionFrom    =JSON.stringify(this.action);
          var actionStorage =JSON.stringify(this.storage);
          $.post(tatiyeNet.etc,{
                 'etc'          :myFrom,
                 'action'       :actionFrom,
                 'storage'      :actionStorage,
                  beforeSend: function() {
                     $("#bodyFrom"+model).html(itemSpinner('modal'));  
                 },
                })
               .done(function (desain) {
                   $("#bodyFrom"+model).html(desain);
                 
                    privacy(row);
                    const setForumStorage = event => {
                             let form =$('#form_'+model).serialize();
                             let db=tatiyeNet.firebase.database().ref('exsampel');
                              const d = new Date();
                              let time = d.getTime();
                              var formdata = $('#form_'+model).serializeArray();
                              var dataFire = {};
                              let keys = Object.keys(action);
                              $(formdata ).each(function(index, obj){
                                  $(keys).each(function(indexKey, objKey){
                                     dataFire[objKey] = obj.value;
                                  });
                              });
                         
                               

                             $.ajax({
                                    "type": 'POST',
                                    "url": tatiyeNet.api+'/v1/package/'+row.route+'/controllers/send/'+row.segment,
                                    "data": form,
                                    "datatype": "json",
                                     "content": 'application/x-www-form-urlencoded',
                                     "headers": {
                                         "Authorization":tatiyeNet.token,
                                         "Key":row.key,
                                         "userid":tatiyeNet.userid,
                                         "fireid":tatiyeNet.oauth.userid+''+time
                                     },
                                    "async": false,
                                     beforeSend: function() {
                                         $("#sendEntri"+model).hide();
                                         $("#endEntri"+model).show();  
                                     },
                                    success: function(add) {
                                              
                                              if (add.hasil !== "sukses") {
                                                      $.each(add.error, function( key, value ) {
                                                         var setId =$('#'+key).text();
                                                         var sedLabel=setId+' '+value;
                                                         $('#info_'+key).html('<span style="color: #f0506e">'+sedLabel+'</span>'); 
                                                                 $("#sendEntri"+model).show();
                                                                 $("#endEntri"+model).hide();
                                                     });
                                                      $.each(add.sukses, function( key, value ) {
                                                         $('#info_'+key).html(' '); 
                                                     });
                                                     
                                              } else {
                                                     $.each(add.sukses, function( key, value ) {
                                                         var label=$('#'+key).text(); 
                                                         $('#info_'+key).html(' '); 
                                                     });
                                                    $("#sendEntri"+model).hide();
                                                    $("#endEntri"+model).show();
                                                    var destroyLoader = setTimeout(function(){
                                                    $("#sendEntri"+model).show();
                                                    $("#endEntri"+model).hide();
                                                      // modal.style.display = "none";
                                                        $("#"+model).html('');
                                                     

                                                          if (row.key=='add') {

                                                          let useragent = {
                                                              id:tatiyeNet.oauth.userid+''+time,
                                                              userid:tatiyeNet.oauth.userid,
                                                              avatar:tatiyeNet.oauth.avatar,
                                                              username:tatiyeNet.oauth.name,
                                                              date:setDateTime("EN"),
                                                              time:setDateTime("jam")
                                                          };
                                                           let margeData = Object.assign({}, dataFire,useragent);
                                                            db.child(tatiyeNet.oauth.userid+''+time).set(margeData);
                                                          } else {
                                                             var rowsetIData =useHandelIDTabel(row.tabel+','+row.key);
                                                              let useragentUpdate = {
                                                                  id:rowsetIData.fireid,
                                                                  userid:tatiyeNet.oauth.userid,
                                                                  avatar:tatiyeNet.oauth.avatar,
                                                                  username:tatiyeNet.oauth.name,
                                                                  date:setDateTime("EN"),
                                                                  time:setDateTime("jam")
                                                              };
                                                               let margeDataUp = Object.assign({}, dataFire,useragentUpdate);
                                                                db.child(rowsetIData.fireid).update(margeDataUp);
                                                                
                                                          }

                                                         
                                                     // window.indexOn.setReload();
                                                    
                                                        if (row.reload==false) {} else {
                                                           reload(row.key);
                                                        }
                                                       
                                                       
                                                 },200);
                                                $('input[type="text"],select, textarea').val('');//kosongkan form
                                                $('input[type="email"],select,form textarea').val('');//kosongkan form
                                                $('input[type="password"], select, textarea').val('');//kosongkan form
                                                $('input[type="radio"]').prop('checked', false); 
                                                $('input[type="checkbox"]').prop('checked', false); 
                                              }
                                      }
                               }); 
                    };

                    let sendEntri =document.querySelectorAll("#sendEntri"+model);
                    sendEntri.forEach(entri => {
                      entri.addEventListener('click', setForumStorage);
                    });
           });
    }


